        L_before[i] = L_before[i - 1] + (s[i - 1] === 'L' ? 1 : 0);
        C_before[i] = C_before[i - 1] + (s[i - 1] === 'C' ? 1 : 0);
        T_before[i] = T_before[i - 1] + (s[i - 1] === 'T' ? 1 : 0);
    }

    const C_after = new Array(len + 1).fill(0);
    const T_after = new Array(len + 1).fill(0);

    for (let i = len - 1; i >= 0; i--) {
        C_after[i] = C_after[i + 1] + (s[i] === 'C' ? 1 : 0);
        T_after[i] = T_after[i + 1] + (s[i] === 'T' ? 1 : 0);
    }

    let original_count = 0;
    for (let j = 0; j < len; j++) {
        if (s[j] === 'C') {
            original_count += L_before[j] * T_after[j + 1];
        }
    }

    let max_add_L = 0;
    for (let i = 0; i <= len; i++) {
        max_add_L = Math.max(max_add_L, C_after[i] * T_after[i]);
    }

    let max_add_C = 0;
    for (let i = 0; i <= len; i++) {
        max_add_C = Math.max(max_add_C, L_before[i] * T_after[i]);
    }

    let max_add_T = 0;
    for (let i = 0; i <= len; i++) {
        max_add_T = Math.max(max_add_T, L_before[i] * C_before[i]);
    }

    const max_add = Math.max(max_add_L, max_add_C, max_add_T);
    return original_count + max_add;
}
